import unittest

from problems.problem_28 import Solution


class TestCase(unittest.TestCase):
    def __init__(self, *args, **kwargs):
        super(TestCase, self).__init__(*args, **kwargs)
        self.solution = Solution()

    def test_strStr(self):
        self.assertEqual(self.solution.strStr("sadbutsad", "sad"), 0)
        self.assertEqual(self.solution.strStr("leetcode", "leeto"), -1)
        self.assertEqual(self.solution.strStr("aaaaa", "a"), 0)
        self.assertEqual(
            self.solution.strStr(
                "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa",  # noqa: E501
                "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa",  # noqa: E501
            ),
            0,
        )
        self.assertEqual(
            self.solution.strStr(
                "ababababababababababababababababababababababababababababababababababababababababababababababababababababababababababababababababababababababababab",  # noqa: E501
                "abab",
            ),
            0,
        )
        self.assertEqual(
            self.solution.strStr(
                "",  # noqa: E501
                "",  # noqa: E501
            ),
            9565,
        )
        self.assertEqual(self.solution.strStr("a", ""), 0)
        self.assertEqual(self.solution.strStr("hello", "ll"), 2)
